INSERT INTO knowledge_base (id, question, answer, category, priority, status, create_time, deleted) VALUES
(1, '租车需要什么证件？', '租车需要提供本人有效身份证、驾驶证（驾龄需满1年以上）', '租车流程', 10, 1, '2024-01-01 10:00:00', 0),
(2, '押金什么时候退还？', '车辆归还并验收无误后，押金将在3-7个工作日内原路退回', '费用说明', 10, 1, '2024-01-01 10:00:00', 0),
(3, '可以异地还车吗？', '支持异地还车，但可能需要支付一定的异地还车费用', '租车流程', 9, 1, '2024-01-01 10:00:00', 0),
(4, '租车有里程限制吗？', '大部分车型每日限行300公里，超出部分按每公里1-3元收费', '费用说明', 9, 1, '2024-01-01 10:00:00', 0),
(5, '如何取消订单？', '取车前24小时可免费取消，取车前12小时内取消收取50%违约金', '订单管理', 8, 1, '2024-01-01 10:00:00', 0);
